#!/bin/bash
# Audit script: phát hiện tiếng Anh trong file tiếng Việt và ngược lại

cd "$(dirname "$0")/.."

echo "=== AUDIT NGÔN NGỮ LẪN ==="
echo ""

# Tìm tất cả file HTML
find . -name "*.html" -type f | sort | while read -r file; do
  # Bỏ qua file trong .git, node_modules
  if [[ "$file" == *".git"* ]] || [[ "$file" == *"node_modules"* ]]; then
    continue
  fi

